      /* <flatten type="Javascript"> */
function onChange$VoucherFilter$Tab(f, e) {f.parentForm.focusWhenTabChanged(['vu_viec_me', 'nh_theo']);}
function active$VoucherFilter$(f) {
  f.add_onResponseComplete(on$Filter$ResponseComplete);
  changeLookupReadonly(f, 'tk');
  changeLookupReadonly(f, 'ma_dvcs');
  f._tabContainer.add_activeTabChanged(onChange$VoucherFilter$Tab);
  f._tabContainer._loaded = true;
  onchange$GroupBy(f.getItem('nh_theo'), true);

  changeLookupReadonly(f, 'vu_viec_me', true);
  changeLookupReadonly(f, 'vu_viec', true);
}
function close$VoucherFilter$(sender) {
  try {sender.remove_onResponseComplete(on$Filter$ResponseComplete);} catch (ex) {}
  try {sender._tabContainer.remove_activeTabChanged(onChange$VoucherFilter$Tab);} catch (ex) {}
}
function on$Filter$ResponseComplete(sender, e) {
  var f = e.object, context = e.type.Context, result = e.type.Result;
  switch (context) {
    case 'Checking':
      var g = f.grid;
      g._hiddenFields = [{Fields: 'no_dk_nt, co_dk_nt, ps_no_nt, ps_co_nt, no_ck_nt, co_ck_nt', Value: (f.getItemValue('mau_bc')) == '10'}];
      g._alterTitle = [null, [['%d1', f.getItem('ngay1').value, true], ['%d2', f.getItem('ngay2').value, true]]];
      g._queryFilterString = getQueryFilterString(f, 'ngay1, ngay2, ma_dvcs, mau_bc');
      remove$GridReport$Filter(g);
      break;
    default:
      break;
  }
}
function onchange$GroupBy(o, force) {
  var f = o.parentForm, v = (f.getItemValue('nh_theo') != '0');
  f.getItem('tt_sx1').disabled = f.getItem('tt_sx3').disabled = f.getItem('tt_sx2').disabled = v;
  if (v && !force) {
    f.setItemValue('tt_sx1', 0);
    f.setItemValue('tt_sx2', 0);
    f.setItemValue('tt_sx3', 0);
  }
}
/* </flatten> */


